const r = $input.first().json.record;
const m = r?.metrics || {};
const lcp = m.largest_contentful_paint?.percentiles?.p75;
const inp = m.interaction_to_next_paint?.percentiles?.p75;
const cls = m.cumulative_layout_shift?.percentiles?.p75;
return [{ json: {
  url: r?.key?.url,
  date: new Date().toISOString().split('T')[0],
  lcp, inp, cls,
  lcpStatus: lcp < 2500 ? 'good' : lcp < 4000 ? 'needs-improvement' : 'poor',
  inpStatus: inp < 200 ? 'good' : inp < 500 ? 'needs-improvement' : 'poor',
  clsStatus: cls < 0.1 ? 'good' : cls < 0.25 ? 'needs-improvement' : 'poor'
} }];
